class Solution {
public:
    int findDuplicate(vector<int>& nums) {
        // 把下标 i -> nums[i] 看作链表的 next 指针，重复数即环的入口
        int slow = 0, fast = 0;
        do {
            slow = nums[slow];
            fast = nums[nums[fast]]; // 快指针每次走两步
        } while (slow != fast);
        slow = 0;
        while (slow != fast) { // 第二阶段：同速前进，相遇点就是环入口
            slow = nums[slow];
            fast = nums[fast];
        }
        return slow;
    }
};
